mapper.select:
SELECT count(*) FROM platform_policies

    AND COALESCE(title, name) LIKE #{title}
    AND COALESCE(policy_category, category) = #{policyCategory}
    AND state_id IN #{item}

SELECT id, COALESCE(title, name) AS title,
       COALESCE(policy_category, category) AS policy_category,
       COALESCE(version_label, version_number) AS version_label,
       state_id, flow_id,
       COALESCE(effective_date, effective_from) AS effective_date,
       summary_text, created_time, last_modified_time, tenant
FROM platform_policies

    AND COALESCE(title, name) LIKE #{title}
    AND COALESCE(policy_category, category) = #{policyCategory}
    AND state_id IN #{item}

${orderby} ${pagination}

SELECT count(*) FROM agreements

    AND COALESCE(title, name) LIKE #{title}
    AND agreement_type = #{agreementType}
    AND state_id IN #{item}
    AND COALESCE(mandatory_acceptance, requires_acceptance) = #{mandatoryAcceptance}

SELECT id, COALESCE(title, name) AS title,
       agreement_type, COALESCE(version_label, version_number) AS version_label,
       state_id, flow_id,
       COALESCE(effective_date, effective_from) AS effective_date,
       COALESCE(expiry_date, effective_until) AS expiry_date,
       COALESCE(mandatory_acceptance, requires_acceptance) AS mandatory_acceptance,
       created_time, last_modified_time, tenant
FROM agreements

    AND COALESCE(title, name) LIKE #{title}
    AND agreement_type = #{agreementType}
    AND state_id IN #{item}
    AND COALESCE(mandatory_acceptance, requires_acceptance) = #{mandatoryAcceptance}

${orderby} ${pagination}

SELECT count(*) FROM agreement_acceptances aa JOIN agreements a ON aa.agreement_id = a.id

    AND aa.agreement_id = #{agreementId}
    AND aa.user_id = #{userId}
    AND aa.user_type = #{userType}
    AND aa.is_current = #{isCurrent}

SELECT aa.id, COALESCE(a.title, a.name) AS agreement_title,
       aa.user_id, aa.user_type, aa.accepted_at,
       aa.acceptance_method, aa.is_current, aa.agreement_id
FROM agreement_acceptances aa JOIN agreements a ON aa.agreement_id = a.id

    AND aa.agreement_id = #{agreementId}
    AND aa.user_id = #{userId}
    AND aa.user_type = #{userType}
    AND aa.is_current = #{isCurrent}

${orderby} ${pagination}

SELECT count(*) FROM regulations

    AND act_name LIKE #{actName}
    AND jurisdiction = #{jurisdiction}
    AND category = #{category}
    AND applicable_to = #{applicableTo}
    AND is_active = #{isActive}

SELECT id, act_name, section, requirement_summary,
       jurisdiction, applicable_to, enforcement_date,
       category, is_active
FROM regulations

    AND act_name LIKE #{actName}
    AND jurisdiction = #{jurisdiction}
    AND category = #{category}
    AND applicable_to = #{applicableTo}
    AND is_active = #{isActive}

${orderby} ${pagination}
